		let text = $(this).text().trim();
		//href = href.replace(/;.*$/g,"");
		if (typeof href == "undefined" || href.length < 3 || /^(javascript|mailto:|ftp:)/ig.test(href)) return;

		let currentUrl = parse(href, baseUrlStr);

